oxy_webhelp_navlinks = {"tocId-d27248e32678":{"topics":[{"title":"Set up Exocompute for GitHub on Azure","shortdesc":"<p class=\"shortdesc\">With the Exocompute for GitHub on Azure feature, <span class=\"ph\">RSC<\/span> launches an         Azure Kubernetes Service (AKS) cluster to perform data protection operations for your GitHub         repositories. <span class=\"ph\">RSC<\/span> uses this AKS cluster as a dedicated compute resource         within your Azure subscription to ensure data sovereignty and efficient         processing.<\/p>","href":"github\/github_set_up_exocompute_azure.html","attributes":{"data-id":"github_set_up_exocompute_azure"},"menu":{"hasChildren":false},"tocID":"github_set_up_exocompute_azure-d27248e32679","topics":[]},{"title":"Set up Exocompute for GitHub on AWS","shortdesc":"<p class=\"shortdesc\">With the Exocompute for GitHub on AWS feature, <span class=\"ph\">RSC<\/span> launches an Amazon         Elastic Kubernetes Service cluster to serve as a dedicated compute resource within your AWS         account. This cluster executes the core logic for data protection operations while ensuring         data remains within your security boundaries.<\/p>","href":"github\/github_set_up_exocompute_aws.html","attributes":{"data-id":"github_set_up_exocompute_aws"},"menu":{"hasChildren":false},"tocID":"github_set_up_exocompute_aws-d27248e32696","topics":[]}]}};